SELECT 
FROM bucket_storage_log
WHERE bucket_name = #{bucketName}
AND stat_date BETWEEN #{startDate} AND #{endDate}
ORDER BY stat_date DESC, stat_hour DESC

SELECT 
FROM bucket_storage_log
WHERE user_id = #{userId}
AND stat_date BETWEEN #{startDate} AND #{endDate}
ORDER BY stat_date DESC, stat_hour DESC
